# -----------------------------------------------------------------------------
# TOTP (RFC 6238) helpers (no external dependency)
# -----------------------------------------------------------------------------
def _normalize_b32(s: str) -> str:
    s = (s or "").strip().replace(" ", "").upper()
    padding = "=" * ((8 - (len(s) % 8)) % 8)
    return s + padding

def _totp_at(secret_b32: str, for_time: int, step: int = 30, digits: int = 6) -> str:
    key = base64.b32decode(_normalize_b32(secret_b32), casefold=True)
    counter = int(for_time // step)
    msg = struct.pack(">Q", counter)
    digest = hmac.new(key, msg, hashlib.sha1).digest()
    offset = digest[-1] & 0x0F
    code_int = struct.unpack(">I", digest[offset:offset + 4])[0] & 0x7FFFFFFF
    code = code_int % (10 ** digits)
    return str(code).zfill(digits)

def verify_totp(secret_b32: str, code: str, window: int = 1, step: int = 30, digits: int = 6) -> bool:
    if not code or not code.isdigit():
        return False
    now = int(time.time())
    for w in range(-window, window + 1):
        if hmac.compare_digest(_totp_at(secret_b32, now + (w * step), step=step, digits=digits), code):
            return True
    return False

