@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "GET":
        next_url = request.args.get("next") or ""
        return jsonify(
            info="POST JSON {username,password} to login",
            next=next_url,
        )

    data = request.get_json(silent=True) or request.form or {}
